<template>
  <h3>Your Browser and Feature Detection</h3>
  <div class="agent-wrapper">
    <div class="agent-wrapper--left">
      <p>Browser</p>
      <p>OS</p>
      <p>Engine Name</p>
      <p>Cpu</p>
    </div>
    <div class="agent-wrapper--right">
      <p>{{ browser.name }} {{ browser.version }}</p>
      <p>{{ os.name }} {{ os.version }}</p>
      <p>{{ engine.name }} {{ engine.version }}</p>
      <p>{{ cpu }}</p>
    </div>
  </div>
</template>

<script>
import { UAParser } from "ua-parser-js";
export default {
  data() {
    return {
      browser: "",
      device: "",
      os: "",
      osVersion: "",
      engine: "",
      cpu: "",
    };
  },
  methods: {
    getAgent: function () {
      var parser = new UAParser();
      // by default it takes ua string from current browser's window.navigator.userAgent
      console.log(parser.getResult());
      var result = parser.getResult();

      this.browser = result.browser; // {name: "Chromium", version: "15.0.874.106"}
      this.device = result.device; // {model: undefined, type: undefined, vendor: undefined}
      this.os = result.os; // {name: "Ubuntu", version: "11.10"}
      this.engine = result.engine; // "WebKit"
      this.cpu = result.cpu.architecture; // "amd64"
    },
  },
  created() {
    this.getAgent();
  },
};
</script>

